import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

// Create colored circle markers
const createCircleIcon = (color) => {
  return L.divIcon({
    className: "custom-div-icon",
    html: `<div style="background-color:${color}; width:15px; height:15px; border-radius:50%; border: 2px solid white;"></div>`,
    iconSize: [15, 15],
    iconAnchor: [7, 7],
  });
};

const MapComponent = () => {
  const [buses, setBuses] = useState([]);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();
        console.log("Fetched buses:", data); // check data
        setBuses(data);
      } catch (error) {
        console.error("Error fetching bus data:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // every 2 minutes
    return () => clearInterval(interval);
  }, []);

  // Count bus types
  const counts = buses.reduce(
    (acc, bus) => {
      if (bus.status === "ghost") acc.ghost += 1;
      else if (bus.status === "anomaly") acc.anomaly += 1;
      else acc.normal += 1;
      return acc;
    },
    { normal: 0, ghost: 0, anomaly: 0 }
  );

  return (
    <>
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={11}
        style={{ height: "100vh", width: "100vw" }}
      >
        <TileLayer
          url="https://tiles.stadiamaps.com/tiles/alidade_smooth/{z}/{x}/{y}{r}.png"
          attribution='&copy; <a href="https://stadiamaps.com/">Stadia Maps</a>'
        />

        {buses
          .filter(bus => bus.lat && bus.lon)
          .map(bus => {
            let color = "green";
            if (bus.status === "ghost") color = "red";
            else if (bus.status === "anomaly") color = "orange";

            return (
              <Marker
                key={bus.id}
                position={[bus.lat, bus.lon]}
                icon={createCircleIcon(color)}
              >
                <Popup>{bus.status.toUpperCase()}</Popup>
              </Marker>
            );
          })}
      </MapContainer>

      {/* Bus counts at bottom-left */}
      <div
        style={{
          position: "absolute",
          bottom: 20,
          left: 20,
          backgroundColor: "rgba(255,255,255,0.8)",
          padding: "10px",
          borderRadius: "8px",
          fontWeight: "bold"
        }}
      >
        Normal: {counts.normal} <br />
        Ghost: {counts.ghost} <br />
        Anomaly: {counts.anomaly}
      </div>
    </>
  );
};

export default MapComponent;
